const input = $input.first().json;
const body = input.body || input;

let source = 'web';
let msg = '';
let sessionId = '';
let userId = '';
let chatId = '';

if (input.message && input.message.text) {
  source = 'telegram';
  msg = input.message.text;
  userId = String(input.message.from?.id || '');
  chatId = String(input.message.chat?.id || '');
  sessionId = 'tg_' + chatId;
} else {
  msg = body.message || body.chatInput || '';
  sessionId = body.sessionId || 'web_' + Math.random().toString(36).slice(2, 11);
  userId = sessionId;
  chatId = sessionId;
}

return [{ json: { msg, sessionId, userId, chatId, source, timestamp: new Date().toISOString() }}];

const prev = $('Normalize Input').first().json;
const msg  = (prev.msg || '').trim();
const { sessionId, userId, chatId, source } = prev;

const lastRec = $input.first()?.json?.fields || {};
const lastVideoId = lastRec.video_id || null;

let lastTests = [];
try { lastTests = lastRec.test_sorulari ? JSON.parse(lastRec.test_sorulari) : []; }
catch(e) { lastTests = []; }

let lastDers = '[]';
try { if (lastRec.ders_anlatimi) JSON.parse(lastRec.ders_anlatimi); lastDers = lastRec.ders_anlatimi || '[]'; }
catch(e) { lastDers = '[]'; }

const ytStrictRegex = /(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/|live\/)|youtu\.be\/)([\w-]{11})/;
const match   = msg.match(ytStrictRegex);
const videoId = match ? match[1] : null;

const lower = msg.toLowerCase().trim();
let intent = 'soru';

if      (videoId)                                                              intent = 'youtube';
else if (lower.startsWith('/help') || lower.startsWith('/start'))             intent = 'help';
else if (lower.startsWith('/history'))                                         intent = 'history';
else if (/^[a-d][.)]\s*$/i.test(lower) && lastTests.length > 0)              intent = 'test_cevap';
else if (lower.includes('test') || lower.includes('quiz'))                    intent = 'test_iste';
else if (lower.includes('özet') || lower.includes('ozet') || lower.includes('summary')) intent = 'ozet_iste';
else if (lower.includes('sade') || lower.includes('basit') || lower.includes('kolay') || lower.includes('simple')) intent = 'sade_anlat';
else if (lower.includes('detay') || lower.includes('derin') || lower.includes('ileri') || lower.includes('advanced')) intent = 'derin_anlat';
else if (lower.includes('ingilizce') || lower.includes('english'))            intent = 'ingilizce';
else if (lower.includes('5 yaş') || lower.includes('çocuk') || lower.includes('cocuk')) intent = 'cocuk';

return [{ json: {
  msg, sessionId, userId, chatId, source,
  videoId, intent, lastVideoId, lastTests,
  lastTitle:    lastRec.title           || '',
  lastOzet:     lastRec.ozet            || '',
  lastDers,
  lastKavramlar: lastRec.anahtar_kavramlar || ''
}}];

const input = $input.first().json;
const prev  = $('Message Analyze').first().json;

let transcript = '';
let lang = 'tr';

if (Array.isArray(input.content)) {
  transcript = input.content.map(s => (s.text || '')).join(' ');
  lang = input.language || 'tr';
} else if (typeof input.content === 'string') {
  transcript = input.content;
} else if (input.transcript) {
  transcript = Array.isArray(input.transcript)
    ? input.transcript.map(s => (s.text || '')).join(' ')
    : String(input.transcript);
}

transcript = transcript.trim();
if (!transcript) {
  return [{ json: { ...prev, error: true, output: '⚠️ Bu video için transkript bulunamadı. Altyazı kapalı olabilir.', transcript: '', lang, charCount: 0 }}];
}

if (transcript.length > 150000) transcript = transcript.substring(0, 150000) + '\n\n[...]';

return [{ json: { ...prev, transcript, lang, charCount: transcript.length }}];

const raw = $input.first().json;
const rec  = raw.fields || raw;
const prev = $('Message Analyze').first().json;

function safeparse(s, fallback) {
  try { return s ? JSON.parse(s) : fallback; }
  catch(e) { return fallback; }
}

const ders_anlatimi      = safeparse(rec.ders_anlatimi,      []);
const test_sorulari      = safeparse(rec.test_sorulari,      []);
const pratik_uygulamalar = safeparse(rec.pratik_uygulamalar, []);
const anahtar_kavramlar  = safeparse(rec.anahtar_kavramlar,  []);

const parsedLesson = {
  video_konusu: rec.title || '',
  seviye:       rec.seviye || '',
  ozet:         rec.ozet   || '',
  ders_anlatimi,
  test_sorulari,
  pratik_uygulamalar,
  anahtar_kavramlar
};

// Formatlı mesaj üret (Format Lesson ile aynı mantık)
const kavramlar = anahtar_kavramlar.map(k => `\`${k}\``).join(' · ');
const anlatim   = ders_anlatimi.map((b, i) =>
  `*${i+1}. ${b.baslik}*\n${b.icerik}${b.onemli_not ? `\n💡 *Not:* ${b.onemli_not}` : ''}`
).join('\n\n');
const pratik    = pratik_uygulamalar.map((u, i) => `${i+1}. ${u}`).join('\n');
const testler   = test_sorulari.map((q, i) => {
  const opts = Object.entries(q.secenekler || {}).map(([k,v]) => `*${k})* ${v}`).join('  |  ');
  return `*Soru ${i+1}:* ${q.soru}\n\n${opts}\n\nCevap: ||${q.dogru_cevap} - ${q.aciklama}||`;
}).join('\n\n---\n\n');

const output = `🎓 *${rec.title || prev.videoId}* _(önbellekten)_\n> Seviye: ${rec.seviye || '-'}\n\n*🔑 Kavramlar:* ${kavramlar || '-'}\n\n*📝 Özet*\n${rec.ozet || '-'}\n\n*📖 Konu Anlatımı*\n${anlatim || '-'}\n\n*🛠️ Pratik*\n${pratik || '-'}\n\n*🧪 Testler*\n${testler || '-'}\n\n💬 _Soru sorabilir veya A/B/C/D yazabilirsin._`;

return [{ json: {
  ...prev,
  cached: true,
  title:  rec.title  || 'Başlıksız',
  seviye: rec.seviye || '',
  ozet:   rec.ozet   || '',
  output,
  parsedLesson
}}];

const d = $input.first().json;
const t = d.transcript || '';
const MAX = 8000;

if (!t || t.length <= MAX) return [{ json: { ...d, chunks: [t], totalChunks: 1 } }];

const chunks = [];
let cur = '';
const sentences = t.match(/[^.!?]+[.!?]+/g) || [t];
for (const s of sentences) {
  if ((cur + s).length > MAX && cur.length > 1000) { chunks.push(cur.trim()); cur = s; }
  else cur += s;
}
if (cur.trim()) chunks.push(cur.trim());

return chunks.map((c, i) => ({ json: { ...d, currentChunk: c, chunkIndex: i, totalChunks: chunks.length } }));

