const agg  = $input.first().json;
const sums = agg.summaries || [];

// base context: Aggregate öncesinden birini al
const base = sums[0] || {};

const combined = sums.map((s, i) => {
  const c = s?.choices?.[0]?.message?.content || s?.message?.content || '';
  return `Bölüm ${i+1}:\n${c}`;
}).join('\n\n---\n\n');

// Message Analyze'dan orijinal meta veriyi al
const meta = $('Message Analyze').first().json;

return [{ json: { ...meta, combinedSummary: combined, totalChunks: sums.length, transcript: '' }}];

