const ai   = $input.first().json;
const base = $('Message Analyze').first().json;

let content = ai?.choices?.[0]?.message?.content || ai?.message?.content || '';

// JSON objesini çıkart
const m = content.match(/\{[\s\S]*\}/);
if (!m) return [{ json: { ...base, error: true, output: '⚠️ AI yapılandırılmış veri döndürmedi. Tekrar deneyin.' }}];

let p;
try {
  p = JSON.parse(m[0]);
} catch(e) {
  try {
    p = JSON.parse(m[0].replace(/,\s*}/g, '}').replace(/,\s*]/g, ']'));
  } catch(e2) {
    return [{ json: { ...base, error: true, output: `⚠️ JSON parse hatası: ${e2.message}` }}];
  }
}

const kavramlar = (p.anahtar_kavramlar || []).map(k => `\`${k}\``).join(' · ');
const onbilgi   = (p.on_bilgi          || []).map(b => `- ${b}`).join('\n');
const anlatim   = (p.ders_anlatimi     || []).map((b, i) =>
  `*${i+1}. ${b.baslik}*\n${b.icerik}${b.onemli_not ? `\n💡 *Not:* ${b.onemli_not}` : ''}`
).join('\n\n');
const pratik    = (p.pratik_uygulamalar || []).map((u, i) => `${i+1}. ${u}`).join('\n');
const testler   = (p.test_sorulari     || []).map((q, i) => {
  const opts = Object.entries(q.secenekler || {}).map(([k,v]) => `*${k})* ${v}`).join('  |  ');
  return `*Soru ${i+1}:* ${q.soru}\n\n${opts}\n\nCevap: ||${q.dogru_cevap} - ${q.aciklama}||`;
}).join('\n\n---\n\n');

const output = `🎓 *${p.video_konusu || base.videoId}*\n> Seviye: ${p.seviye} | Hedef: ${p.hedef_kitle}\n\n*⏱️ ${p.sure_ozet}*\n\n*🔑 Kavramlar:* ${kavramlar}\n\n*📚 Ön bilgi:*\n${onbilgi}\n\n*📝 Özet*\n${p.ozet}\n\n*📖 Konu Anlatımı*\n${anlatim}\n\n*🛠️ Pratik*\n${pratik}\n\n*🧪 Testler*\n${testler}\n\n*🔍 Araştır*\n${(p.ilgili_konular||[]).map(k=>`- ${k}`).join('\n')}\n\n💬 _Soru sorabilir veya A/B/C/D yazabilirsin._`;

return [{ json: {
  ...base,
  error: false,
  output,
  title:        p.video_konusu || base.videoId,
  seviye:       p.seviye       || '',
  ozet:         p.ozet         || '',
  parsedLesson: p
}}];

