const data   = $input.first().json;
const prev   = $('Message Analyze').first().json;
const answer = data?.choices?.[0]?.message?.content || data?.message?.content || '';

if (!answer || answer.trim() === '') {
  return [{ json: { ...prev, output: '⚠️ Cevap üretilemedi. Tekrar deneyin.' }}];
}

const intentLabel = {
  soru:        '💬',
  test_iste:   '🧪',
  ozet_iste:   '📝',
  sade_anlat:  '🟢',
  derin_anlat: '🔵',
  ingilizce:   '🇬🇧',
  cocuk:       '🧒'
}[prev.intent] || '💬';

return [{ json: { ...prev, output: `${intentLabel} ${answer}` }}];

const data  = $input.first().json;
const tests = data.lastTests || [];
const msg   = (data.msg || '').trim().toUpperCase();
const answer = msg.replace(/[^A-D]/g, '').charAt(0);

if (!tests.length) {
  return [{ json: { ...data, output: '❌ Aktif test bulunamadı. Önce bir YouTube videosu analiz ettirin.' }}];
}
if (!answer) {
  return [{ json: { ...data, output: '⚠️ Geçerli bir seçenek girin: A, B, C veya D' }}];
}

// Son yanlış cevabı vermediğimiz (veya henüz cevap verilmemiş) ilk soruyu bul
const unanswered = tests.find(q => !q._answered);
const q = unanswered || tests[0];

const isCorrect = (q.dogru_cevap || '').toUpperCase() === answer;

const opts = Object.entries(q.secenekler || {})
  .map(([k, v]) => `${k === answer ? (isCorrect ? '✅' : '❌') : (k === q.dogru_cevap && !isCorrect ? '✅' : '•')} *${k})* ${v}`)
  .join('\n');

const result = isCorrect
  ? `✅ *Doğru!*\n\n${opts}\n\n💡 ${q.aciklama}`
  : `❌ *Yanlış.* (Senin cevabın: ${answer} | Doğru: ${q.dogru_cevap})\n\n${opts}\n\n💡 ${q.aciklama}`;

// Sonraki soruyu göster (varsa)
const currentIdx = tests.indexOf(q);
const nextQ      = tests[currentIdx + 1];
const nextHint   = nextQ
  ? `\n\n*Soru ${currentIdx + 2}/${tests.length}:* ${nextQ.soru}\n\n${Object.entries(nextQ.secenekler||{}).map(([k,v])=>`*${k})* ${v}`).join('  |  ')}\n\nCevabın?`
  : `\n\n🏁 *Tüm sorular tamamlandı!* Yeni bir video analiz etmek için link gönder.`;

return [{ json: { ...data, output: `*Soru ${currentIdx + 1}/${tests.length}*\n\n${result}${nextHint}` }}];

const d = $input.first().json;
const helpMsg = `👋 *YouTube AI Master*

• YouTube linki → Ders planı + test
• Soru sor → Son videoyla ilgili cevap veririm
• A/B/C/D → Test cevabını kontrol ederim
• /history → Geçmişin

Örnek: https://youtube.com/watch?v=...`;
return [{ json: { ...d, output: helpMsg }}];

const recs = $input.all();
const d = $('Message Analyze').first().json;
if (!recs.length) return [{ json: { ...d, output: 'Henüz geçmiş yok.' }}];
let text = '*📋 Son 5 Analiz:*\n\n';
recs.forEach((r,i)=>{ const f=r.json.fields||r.json; text+=`${i+1}. *${f.title||'-'}* (${f.seviye||'-'})\n${f.video_id ? 'https://youtube.com/watch?v='+f.video_id : ''}\n\n`; });
return [{ json: { ...d, output: text }}];

const d    = $input.first().json;
const text = (d.output || d.historyMessage || d.helpMessage || 'Tamam.').trim();

// Web kaynaklı istekler için düz metin dön
if (d.source !== 'telegram') {
  return [{ json: { ...d, telegramHtml: '', response: text }}];
}

// Telegram HTML dönüşümü
// Sıra önemli: önce **bold**, sonra *bold*, sonra `code`, sonra spoiler
let html = text
  .replace(/\*\*([^*\n]+)\*\*/g,   '<b>$1</b>')
  .replace(/\*((?:[^*\n]|\n(?!\n))+)\*/g, '<b>$1</b>')
  .replace(/`([^`\n]+)`/g,          '<code>$1</code>')
  .replace(/\|\|(.+?)\|\|/gs,       '<tg-spoiler>$1</tg-spoiler>')
  .replace(/_([^_\n]+)_/g,          '<i>$1</i>');

// Telegram'ın 4096 karakter limitini yönet
if (html.length > 4000) {
  html = html.substring(0, 3900) + '\n\n<i>✂️ [Mesaj kesildi — /history ile tam listeye bak]</i>';
}

return [{ json: { ...d, telegramHtml: html, response: text }}];
